const items = $input.all();
const results = [];
for (const item of items) {
  const body = item.json.body || item.json;
  const data = body.data || {};
  const key = data.key || {};
  const message = data.message || {};
  const messageType = data.messageType || '';
  const isAudio = messageType === 'audioMessage' || messageType === 'pttMessage';
  const isImage = messageType === 'imageMessage';
  const telefono = (key.remoteJid || '').replace('@s.whatsapp.net', '').replace('@g.us', '');

  if (!telefono) continue;

  const nombreWhatsApp = data.pushName || 'Cliente';
  let messageText = '';
  if (message.conversation) {
    messageText = message.conversation;
  } else if (message.extendedTextMessage && message.extendedTextMessage.text) {
    messageText = message.extendedTextMessage.text;
  } else if (message.imageMessage && message.imageMessage.caption) {
    messageText = message.imageMessage.caption;
  }
  const rawMessage = JSON.parse(JSON.stringify(message));
  const rawKey = JSON.parse(JSON.stringify(key));
  const instance = String(body.instance || '');
  results.push({ json: { telefono, nombreWhatsApp, messageText, isAudio, isImage, rawMessage, rawKey, instance } });
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const config = item.json.config;
  const rawKey = item.json.rawKey;
  const rawMessage = item.json.rawMessage;
  const caption = (rawMessage.imageMessage && rawMessage.imageMessage.caption) || '';
  try {
    const b64Response = await $helpers.httpRequest({
      method: 'POST',
      url: `${config.EVOLUTION_API_URL}/chat/getBase64FromMediaMessage/${encodeURIComponent(config.EVOLUTION_INSTANCE)}`,
      headers: { 'Content-Type': 'application/json', 'apikey': config.EVOLUTION_API_KEY },
      body: { message: { key: rawKey, message: rawMessage }, convertToMp4: false },
      bodyContentType: 'json'
    });
    const base64Image = b64Response.base64;
    if (!base64Image) throw new Error('No base64');
    const visionRes = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: { 'Authorization': `Bearer ${config.OPENAI_API_KEY}`, 'Content-Type': 'application/json' },
      body: {
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: [
          { type: 'image_url', image_url: { url: `data:image/jpeg;base64,${base64Image}` } },
          { type: 'text', text: 'Esta imagen fue enviada por un cliente de una tienda de repostería como referencia del diseño que desea. Describe en 1-2 oraciones qué muestra la imagen (personaje, logo, tema, colores principales, estilo), de forma concisa para que la asistente pueda anotarlo como diseño del pedido.' }
        ]}],
        max_tokens: 150
      },
      bodyContentType: 'json'
    });
    const desc = visionRes.choices[0].message.content;
    const messageText = caption
      ? `[El cliente envió una imagen como referencia del diseño que desea: ${desc}] Mensaje adicional del cliente: "${caption}"`
      : `[El cliente envió una imagen como referencia del diseño que desea: ${desc}]`;
    results.push({ json: { ...item.json, messageText } });
  } catch(err) {
    const fallback = caption
      ? `[El cliente envió una imagen como referencia de diseño, pero no se pudo procesar] Mensaje del cliente: "${caption}"`
      : '[El cliente envió una imagen como referencia del diseño que desea, pero no se pudo procesar. Pídele que describa el diseño con palabras.]';
    results.push({ json: { ...item.json, messageText: fallback } });
  }
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const config = item.json.config;
  const rawKey = item.json.rawKey;
  const rawMessage = item.json.rawMessage;
  try {
    const base64Response = await $helpers.httpRequest({
      method: 'POST',
      url: `${config.EVOLUTION_API_URL}/chat/getBase64FromMediaMessage/${encodeURIComponent(config.EVOLUTION_INSTANCE)}`,
      headers: { 'Content-Type': 'application/json', 'apikey': config.EVOLUTION_API_KEY },
      body: { message: { key: rawKey, message: rawMessage }, convertToMp4: false },
      bodyContentType: 'json'
    });
    const base64Audio = base64Response.base64;
    if (!base64Audio) throw new Error('No base64');
    const FormData = require('form-data');
    const form = new FormData();
    form.append('file', Buffer.from(base64Audio, 'base64'), { filename: 'audio.ogg', contentType: 'audio/ogg' });
    form.append('model', 'whisper-1');
    form.append('language', 'es');
    const whisperResponse = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/audio/transcriptions',
      headers: { 'Authorization': `Bearer ${config.OPENAI_API_KEY}`, ...form.getHeaders() },
      body: form,
      bodyContentType: 'raw'
    });
    results.push({ json: { ...item.json, messageText: whisperResponse.text || '[audio no transcribible]' } });
  } catch(err) {
    results.push({ json: { ...item.json, messageText: '[No pude entender el audio, por favor escríbeme tu mensaje]' } });
  }
}
return results;

const items = $input.all();
const results = [];
for (const item of items) {
  const output = item.json.output || '';
  const telefono = $('Extraer mensaje').first().json.telefono;
  const config = $('Config Mochas Place').first().json.config;
  const orderRegex = /\[ORDER_COMPLETE:(\{[\s\S]*?\})\]/;
  const match = output.match(orderRegex);
  let pedido = null;
  let respuesta = output;
  if (match) {
    try {
      pedido = JSON.parse(match[1]);
      pedido.telefono = telefono;
      respuesta = output.replace(orderRegex, '').trim();
    } catch(e) { }
  }
  const notificationText = pedido ?
    `NUEVO PEDIDO - Mocha's Place\n\nCliente: ${pedido.nombre || 'No especificado'}\nTeléfono: ${telefono}\nProducto: ${pedido.producto || ''}\nCantidad: ${pedido.cantidad || ''}\nPersonalización: ${pedido.personalizacion || ''}\nEntrega: ${pedido.metodo_entrega || ''}\nNotas: ${pedido.notas || ''}` : '';
  results.push({ json: { telefono, respuesta, pedido, hayPedido: !!pedido, notificationText, config } });
}
return results;

